import{_ as d,o as t,c as o,a2 as a}from"./chunks/framework.Fbjs98zA.js";const b=JSON.parse('{"title":"@mango/job Views","description":"","frontmatter":{},"headers":[],"relativePath":"mango-ui/packages/job/src/views/README.md","filePath":"mango-ui/packages/job/src/views/README.md"}'),i={name:"mango-ui/packages/job/src/views/README.md"};function s(c,e,n,r,l,h){return t(),o("div",null,[...e[0]||(e[0]=[a(`<h1 id="mango-job-views" tabindex="-1">@mango/job Views <a class="header-anchor" href="#mango-job-views" aria-label="Permalink to &quot;@mango/job Views&quot;">​</a></h1><h2 id="_1-概览" tabindex="-1">1. 概览 <a class="header-anchor" href="#_1-概览" aria-label="Permalink to &quot;1. 概览&quot;">​</a></h2><p><code>src/views</code> 是 <code>@mango/job</code> 提供给 Mango Admin Shell 的任务调度管理页面集合。它们是 <strong>admin-pages 配套页面</strong>，不是公共业务组件，也不适合官网、C 端站点或非 Mango Admin 的页面复用。</p><p>页面依赖：</p><ul><li><code>@mango/admin-pages</code> 注册和菜单 component key。</li><li><code>@mango/common/utils/request</code> 请求封装。</li><li>Element Plus 表格、表单、弹窗、抽屉和消息组件。</li><li>后端 <code>mango-platform/mango-job</code> 的 <code>/job/**</code> API。</li><li>后端 authorization 菜单和按钮权限。</li></ul><h2 id="_2-功能清单" tabindex="-1">2. 功能清单 <a class="header-anchor" href="#_2-功能清单" aria-label="Permalink to &quot;2. 功能清单&quot;">​</a></h2><p>页面 key 来自 <code>src/admin-pages.ts</code>，菜单入库来自后端 <code>resource-manifest.json</code>。</p><table tabindex="0"><thead><tr><th>页面 key</th><th>文件</th><th>导出</th><th>管理能力</th></tr></thead><tbody><tr><td><code>job/definition/index</code></td><td><code>views/definition/index.vue</code></td><td><code>JobDefinitionView</code></td><td>任务定义列表、筛选、新增、编辑草稿、删除草稿、状态调整、手动触发、参数 JSON 编辑</td></tr><tr><td><code>job/instance/index</code></td><td><code>views/instance/index.vue</code></td><td><code>JobInstanceView</code></td><td>执行实例列表、任务筛选、实例同步、实例日志抽屉、日志自动刷新</td></tr><tr><td><code>job/worker/index</code></td><td><code>views/worker/index.vue</code></td><td><code>JobWorkerView</code></td><td>Worker 快照列表、手动登记 HTTP Worker、Worker 状态治理</td></tr><tr><td><code>job/alarm/index</code></td><td><code>views/alarm/index.vue</code></td><td><code>JobAlarmView</code></td><td>失败实例告警规则列表、新增、编辑、启停、删除、任务范围选择、通知参数编辑</td></tr><tr><td><code>job/engine/index</code></td><td><code>views/engine/index.vue</code></td><td><code>JobEngineView</code></td><td>Mango 原生引擎同步状态统计</td></tr></tbody></table><p>页面组件不定义对外 props 或事件。业务项目按菜单 component key 接入，不把这些页面当作二次开发表单嵌入。</p><h2 id="_3-页面入口" tabindex="-1">3. 页面入口 <a class="header-anchor" href="#_3-页面入口" aria-label="Permalink to &quot;3. 页面入口&quot;">​</a></h2><p>宿主 Admin 启动入口：</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { registerMangoJobAdminPages } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@mango/job/admin-pages&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@mango/job/style.css&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">registerMangoJobAdminPages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><p>菜单资源的 <code>component</code> 字段使用页面 key，例如：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;menuName&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;任务定义&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;path&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/job/definition&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;component&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;job/definition/index&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;permissions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;job:definition:list&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>后端 <code>mango-job-starter</code> 已在 <code>META-INF/mango/resource-manifest.json</code> 声明这些菜单。通常不需要业务项目手写菜单 SQL，只需要确保 authorization 的 manifest 同步和角色授权生效。</p><h2 id="_4-后端依赖" tabindex="-1">4. 后端依赖 <a class="header-anchor" href="#_4-后端依赖" aria-label="Permalink to &quot;4. 后端依赖&quot;">​</a></h2><table tabindex="0"><thead><tr><th>页面</th><th>主要接口</th></tr></thead><tbody><tr><td>任务定义</td><td><code>GET /job/definitions/page</code>、<code>POST /job/definitions</code>、<code>PUT /job/definitions</code>、<code>PUT /job/definitions/status</code>、<code>DELETE /job/definitions</code>、<code>POST /job/definitions/trigger</code>、<code>GET /job/handlers</code></td></tr><tr><td>执行实例</td><td><code>GET /job/instances/page</code>、<code>POST /job/instances/sync</code>、<code>GET /job/instances/{instanceId}/logs</code>、<code>GET /job/definitions/page</code></td></tr><tr><td>Worker 节点</td><td><code>GET /job/workers/page</code>、<code>POST /job/workers</code>、<code>PUT /job/workers/status</code></td></tr><tr><td>告警规则</td><td><code>GET /job/alarm-rules/page</code>、<code>GET /job/alarm-rules/detail</code>、<code>POST /job/alarm-rules</code>、<code>PUT /job/alarm-rules</code>、<code>PUT /job/alarm-rules/status</code>、<code>DELETE /job/alarm-rules</code>、<code>GET /job/definitions/page</code></td></tr><tr><td>运行状态</td><td><code>GET /job/engines/status</code></td></tr></tbody></table><p>接口封装统一在 <code>../api/job.ts</code> 的 <code>jobApi</code> 中。页面只依赖 <code>jobApi</code>，不直接拼接底层 request。</p><h2 id="_5-页面里的关键字段" tabindex="-1">5. 页面里的关键字段 <a class="header-anchor" href="#_5-页面里的关键字段" aria-label="Permalink to &quot;5. 页面里的关键字段&quot;">​</a></h2><p>任务定义页面保存 <code>SaveJobDefinitionPayload</code>：</p><table tabindex="0"><thead><tr><th>字段</th><th>页面含义</th></tr></thead><tbody><tr><td><code>appCode</code></td><td>所属应用</td></tr><tr><td><code>ownerService</code></td><td>执行服务编码；为空时后端按 <code>appCode</code> 处理</td></tr><tr><td><code>workerGroup</code></td><td>Worker 分组；为空时后端按 <code>ownerService</code> 处理</td></tr><tr><td><code>jobCode</code></td><td>任务编码</td></tr><tr><td><code>jobName</code></td><td>任务名称</td></tr><tr><td><code>jobType</code></td><td>当前只支持 <code>BUILTIN</code></td></tr><tr><td><code>scheduleType</code></td><td><code>CRON</code>、<code>FIXED_RATE</code>、<code>ONE_TIME</code>、<code>MANUAL</code></td></tr><tr><td><code>scheduleExpression</code></td><td>调度表达式；<code>MANUAL</code> 可为空</td></tr><tr><td><code>handlerName</code></td><td>处理器名称</td></tr><tr><td><code>paramSchema</code></td><td>参数表单 schema JSON</td></tr><tr><td><code>paramValue</code></td><td>默认参数 JSON</td></tr><tr><td><code>engineType</code></td><td>当前只支持 <code>MANGO_NATIVE</code></td></tr></tbody></table><p><code>views/definition/JobParamEditor.vue</code> 只在任务定义页面内部使用，用于编辑参数 schema 和默认参数；它没有从 package 主入口导出，不是公共组件。</p><p>Worker 页面登记 <code>CreateJobWorkerPayload</code>，只支持手动登记 <code>HTTP_INTERNAL</code> Worker。内嵌 Worker 和远程 Worker 自动注册由后端运行时完成。</p><p>告警页面保存 <code>SaveJobAlarmRulePayload</code>，告警类型当前只支持 <code>INSTANCE_FAILED</code>。通知参数 JSON 支持 <code>userId</code>、<code>userIds</code>、<code>recipientRuleCode</code>，最终由后端 <code>mango-notice</code> 发送。</p><h2 id="_6-管理入口" tabindex="-1">6. 管理入口 <a class="header-anchor" href="#_6-管理入口" aria-label="Permalink to &quot;6. 管理入口&quot;">​</a></h2><p>页面入口权限来自后端 manifest：</p><table tabindex="0"><thead><tr><th>页面</th><th>入口权限</th><th>操作权限</th></tr></thead><tbody><tr><td>任务定义</td><td><code>job:definition:list</code></td><td><code>job:definition:query</code>、<code>job:definition:add</code>、<code>job:definition:edit</code>、<code>job:definition:delete</code>、<code>job:definition:status</code>、<code>job:definition:trigger</code></td></tr><tr><td>执行实例</td><td><code>job:instance:list</code></td><td><code>job:instance:sync</code>、<code>job:log:list</code></td></tr><tr><td>Worker 节点</td><td><code>job:worker:list</code></td><td><code>job:worker:add</code>、<code>job:worker:status</code></td></tr><tr><td>告警规则</td><td><code>job:alarm:list</code></td><td><code>job:alarm:query</code>、<code>job:alarm:add</code>、<code>job:alarm:edit</code>、<code>job:alarm:status</code>、<code>job:alarm:delete</code></td></tr><tr><td>运行状态</td><td><code>job:engine:list</code></td><td>无额外写操作</td></tr></tbody></table><p>前端页面可以按按钮权限展示操作入口，但最终权限、租户和数据边界由后端 <code>/job/**</code> 接口校验。</p><h2 id="_7-问题排查" tabindex="-1">7. 问题排查 <a class="header-anchor" href="#_7-问题排查" aria-label="Permalink to &quot;7. 问题排查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>原因</th><th>处理</th></tr></thead><tbody><tr><td>菜单打开空白</td><td>页面 key 未注册</td><td>确认调用 <code>registerMangoJobAdminPages()</code></td></tr><tr><td>页面能打开但样式异常</td><td>未引入样式</td><td>引入 <code>@mango/job/style.css</code></td></tr><tr><td>列表 404</td><td>后端没有启用 <code>mango-job-starter</code> 或代理未转发 <code>/job</code></td><td>检查后端依赖和网关</td></tr><tr><td>创建任务后触发失败</td><td>handler 归属字段与 Worker 能力不匹配</td><td>对齐 <code>appCode</code>、<code>ownerService</code>、<code>workerGroup</code>、<code>handlerName</code>、<code>jobCode</code></td></tr><tr><td>日志抽屉一直刷新但无内容</td><td>实例未执行完成或日志尚未归档</td><td>检查实例状态、Worker 在线状态和后端日志</td></tr><tr><td>告警规则保存成功但无通知</td><td><code>mango-notice</code> 未启用或通知接收人配置不对</td><td>检查后端实例日志和 <code>noticeParams</code></td></tr></tbody></table><h2 id="_8-相关文档" tabindex="-1">8. 相关文档 <a class="header-anchor" href="#_8-相关文档" aria-label="Permalink to &quot;8. 相关文档&quot;">​</a></h2><ul><li><a href="./../../README">@mango/job</a></li><li><a href="./../../../../../mango/mango-platform/mango-job/README">Mango Job 后端模块</a></li><li><a href="./../../../../../mango-pmo/rules/08-capability-docs">能力说明维护规范</a></li></ul>`,32)])])}const k=d(i,[["render",s]]);export{b as __pageData,k as default};
